import type { AdapterConfig } from "../core/adapter.js";
import { createResumePrompt as createBasePrompt } from "../core/adapter.js";

export function createResumePrompt(config: AdapterConfig): string {
  const base = createBasePrompt(config);

  const header = [
    "<!-- CLAUDE CODE RESUME PROMPT -->",
    "This prompt was generated by ContextPilot.",
    "Claude, please read the entire project state below and continue work.",
    "",
  ].join("\n");

  return header + "\n" + base;
}
